import { Router } from 'express';
import { appointmentController } from '../controllers/appointment.controller';
import { requireAuth } from '../auth';
import { requireUser, requireConsultant } from '../roleMiddleware';
const router = Router();
router.post('/book', requireAuth, requireUser, appointmentController.book);
router.get('/user', requireAuth, requireUser, appointmentController.getUserAppointments);
router.get('/consultant', requireAuth, requireConsultant, appointmentController.getConsultantAppointments);
router.put('/:id/status', requireAuth, requireConsultant, appointmentController.updateStatus);
router.delete('/:id', requireAuth, requireUser, appointmentController.cancel);
export default router;
